641 /// Prepares a use bitset for the given mask either for the first argument or
642 /// for the second.
643 static SmallBitVector buildUseMask(int VF, ArrayRef<int> Mask,
644                                    UseMask MaskArg) {
645   SmallBitVector UseMask(VF, true);
646   for (auto [Idx, Value] : enumerate(Mask)) {
647     if (Value == PoisonMaskElem) {
648       if (MaskArg == UseMask::UndefsAsMask)
649         UseMask.reset(Idx);
650       continue;
651     }
652     if (MaskArg == UseMask::FirstArg && Value < VF)
653       UseMask.reset(Value);
654     else if (MaskArg == UseMask::SecondArg && Value >= VF)
655       UseMask.reset(Value - VF);
656   }
657   return UseMask;
