 848 /// Helper class that determines VL can use the same opcode.
 849 /// Alternate instruction is supported. In addition, it supports interchangeable
 850 /// instruction. An interchangeable instruction is an instruction that can be
 851 /// converted to another instruction with same semantics. For example, x << 1 is
 852 /// equal to x * 2. x * 1 is equal to x | 0.
 853 class BinOpSameOpcodeHelper {
 854   using MaskType = std::uint_fast16_t;
 855   /// Sort SupportedOp because it is used by binary_search.
 856   constexpr static std::initializer_list<unsigned> SupportedOp = {
 857       Instruction::Add,  Instruction::Sub, Instruction::Mul, Instruction::Shl,
 858       Instruction::AShr, Instruction::And, Instruction::Or,  Instruction::Xor};
 859   enum : MaskType {
 860     ShlBIT = 0b1,
 861     AShrBIT = 0b10,
 862     MulBIT = 0b100,
 863     AddBIT = 0b1000,
 864     SubBIT = 0b10000,
 865     AndBIT = 0b100000,
 866     OrBIT = 0b1000000,
 867     XorBIT = 0b10000000,
 868     MainOpBIT = 0b100000000,
 869     LLVM_MARK_AS_BITMASK_ENUM(MainOpBIT)
