1446 static bool hasHardUserWithinLoop(const Loop *L, const Instruction *I) {
1447   SmallPtrSet<const Instruction *, 8> Visited;
1448   SmallVector<const Instruction *, 8> WorkList;
1449   Visited.insert(I);
1450   WorkList.push_back(I);
1451   while (!WorkList.empty()) {
1452     const Instruction *Curr = WorkList.pop_back_val();
1453     // This use is outside the loop, nothing to do.
1454     if (!L->contains(Curr))
1455       continue;
1456     // Do we assume it is a "hard" use which will not be eliminated easily?
1457     if (Curr->mayHaveSideEffects())
1458       return true;
1459     // Otherwise, add all its users to worklist.
1460     for (const auto *U : Curr->users()) {
1461       auto *UI = cast<Instruction>(U);
1462       if (Visited.insert(UI).second)
1463         WorkList.push_back(UI);
1464     }
1465   }
1466   return false;
1467 }
