1484 // Check whether it is possible to delete the loop after rewriting exit
1485 // value. If it is possible, ignore ReplaceExitValue and do rewriting
1486 // aggressively.
1487 static bool canLoopBeDeleted(Loop *L, SmallVector<RewritePhi, 8> &RewritePhiSet) {
1488   BasicBlock *Preheader = L->getLoopPreheader();
1489   // If there is no preheader, the loop will not be deleted.
1490   if (!Preheader)
1491     return false;
1492 
1493   // In LoopDeletion pass Loop can be deleted when ExitingBlocks.size() > 1.
1494   // We obviate multiple ExitingBlocks case for simplicity.
1495   // TODO: If we see testcase with multiple ExitingBlocks can be deleted
1496   // after exit value rewriting, we can enhance the logic here.
1497   SmallVector<BasicBlock *, 4> ExitingBlocks;
1498   L->getExitingBlocks(ExitingBlocks);
1499   SmallVector<BasicBlock *, 8> ExitBlocks;
1500   L->getUniqueExitBlocks(ExitBlocks);
1501   if (ExitBlocks.size() != 1 || ExitingBlocks.size() != 1)
1502     return false;
1503 
1504   BasicBlock *ExitBlock = ExitBlocks[0];
1505   BasicBlock::iterator BI = ExitBlock->begin();
1506   while (PHINode *P = dyn_cast<PHINode>(BI)) {
1507     Value *Incoming = P->getIncomingValueForBlock(ExitingBlocks[0]);
1508 
1509     // If the Incoming value of P is found in RewritePhiSet, we know it
1510     // could be rewritten to use a loop invariant value in transformation
1511     // phase later. Skip it in the loop invariant check below.
1512     bool found = false;
1513     for (const RewritePhi &Phi : RewritePhiSet) {
1514       unsigned i = Phi.Ith;
1515       if (Phi.PN == P && (Phi.PN)->getIncomingValue(i) == Incoming) {
1516         found = true;
1517         break;
1518       }
1519     }
1520 
1521     Instruction *I;
1522     if (!found && (I = dyn_cast<Instruction>(Incoming)))
1523       if (!L->hasLoopInvariantOperands(I))
1524         return false;
1525 
1526     ++BI;
1527   }
1528 
1529   for (auto *BB : L->blocks())
1530     if (llvm::any_of(*BB, [](Instruction &I) {
1531           return I.mayHaveSideEffects();
1532         }))
1533       return false;
1534 
1535   return true;
1536 }
