1552 int llvm::rewriteLoopExitValues(Loop *L, LoopInfo *LI, TargetLibraryInfo *TLI,
1553                                 ScalarEvolution *SE,
1554                                 const TargetTransformInfo *TTI,
1555                                 SCEVExpander &Rewriter, DominatorTree *DT,
1556                                 ReplaceExitVal ReplaceExitValue,
1557                                 SmallVector<WeakTrackingVH, 16> &DeadInsts) {
1558   // Check a pre-condition.
1559   assert(L->isRecursivelyLCSSAForm(*DT, *LI) &&
1560          "Indvars did not preserve LCSSA!");
