1565   SmallVector<RewritePhi, 8> RewritePhiSet;
1566   // Find all values that are computed inside the loop, but used outside of it.
1567   // Because of LCSSA, these values will only occur in LCSSA PHI Nodes.  Scan
1568   // the exit blocks of the loop to find them.
1569   for (BasicBlock *ExitBB : ExitBlocks) {
1570     // If there are no PHI nodes in this exit block, then no values defined
1571     // inside the loop are used on this path, skip it.
1572     PHINode *PN = dyn_cast<PHINode>(ExitBB->begin());
1573     if (!PN) continue;
1574 
1575     unsigned NumPreds = PN->getNumIncomingValues();
1576 
1577     // Iterate over all of the PHI nodes.
1578     BasicBlock::iterator BBI = ExitBB->begin();
1579     while ((PN = dyn_cast<PHINode>(BBI++))) {
1580       if (PN->use_empty())
1581         continue; // dead use, don't replace it
